class ContextWindowAssertion(dspy.Assert):
    def __init__(self, max_tokens=120_000):
        self.max_tokens = max_tokens

    def __call__(self, example, pred, trace=None):
        # Reconstruct full prompt context
        full_prompt = trace.get('prompt', '') + str(example)
        tokens = len(tiktoken_enc.encode(full_prompt))

        if tokens > self.max_tokens:
            return dspy.AssertionFailure(
                f"Context overflow: {tokens}/{self.max_tokens} tokens"
            )
        return True

