class TokenAwareFewShot(dspy.modules.ExampleGenerator):
    def __init__(self, max_tokens=20_000, **kwargs):
        super().__init__(**kwargs)
        self.max_tokens = max_tokens

    def forward(self, example, **kwargs):
        demos = super().forward(example, **kwargs)

        # Truncate to token budget
        demo_prompts = []
        total_tokens = 0

        for demo in demos:
            demo_tokens = len(tiktoken_enc.encode(str(demo)))
            if total_tokens + demo_tokens < self.max_tokens:
                demo_prompts.append(demo)
                total_tokens += demo_tokens
            else:
                break

        return demo_prompts[:4]  # Safety limit

# Replace default example generator
program.example_generator = TokenAwareFewShot(max_tokens=15_000)

