class ContextCompressor(dspy.Module):
    def __init__(self):
        super().__init__()
        self.compress = dspy.ChainOfThought(compress_context)

    def forward(self, context: str, max_tokens: int = 8_000) -> str:
        context_tokens = len(tiktoken_enc.encode(context))

        if context_tokens <= max_tokens:
            return context

        # Two-stage compression
        summary = self.compress(context=context)
        final_tokens = len(tiktoken_enc.encode(summary))

        if final_tokens <= max_tokens * 0.8:
            return summary

        # Ultra-compression
        ultra_prompt = f"Ultra-compress (≤{max_tokens}): {summary}"
        return dspy.ChainOfThought(compress_context)(context=ultra_prompt)

